export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期一。清晨五點四十幾分。灣岸。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她比六點早到了。計程車把她放在步道入口。她沿著欄杆走，走到能看見東京灣人工島方向的位置。風從海面吹上來，帶著金屬和鹹水的味道。很冷。她把外套拉鏈拉到最高。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她低頭看水面。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "東京灣的水很黑。不是深藍。不是墨綠。是黑。平的。沒有波紋。像她夢裡那片海。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯一樣的。", background: Background.Chapter_4_Ch4_Act8_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她抓著欄杆的手指收緊了。她告訴自己那是巧合。東京灣本來就黑。清晨光線不夠。水面沒有燈。是巧合。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說服自己。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "06:12。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "街頭螢幕先動了。對面大樓外牆的公共顯示器從廣告畫面切換成藍底白字。同一秒，月台方向的看板也跳了。車站廣播響起來——不是平常的進站提示，是那種平的、沒有起伏的防災測試語調。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "防災同步測試。防災同步測試。請各位市民配合。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著對面大樓的螢幕。藍底白字。穩定。同步。所有公共螢幕同時切換，像被同一隻手按下去的。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後她等自己的手機。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一秒。兩秒。三秒。四秒。五秒。六秒。七秒。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機震了。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Message, character: "訊息", dialogue: "防災同步測試。防災同步測試。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）七秒。", background: Background.Chapter_4_Ch4_Act8_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手機比街上所有公共螢幕晚了七秒。不是第一次了。上週的測試也是。每一次都是。她以為是手機的問題，是推播延遲，是網路。但現在所有螢幕都在她面前同時亮著，而她的手機剛剛才震——整整晚了七秒。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）不是我的手機慢。是別的東西比我的手機快。是這些公共系統在同步。而我的手機不在那個同步裡。", background: Background.Chapter_4_Ch4_Act8_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她還沒想完。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遠處。東京灣人工島方向。白光。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "沒有聲音。沒有爆炸。沒有衝擊波。沒有熱。她的臉沒有被灼傷。她的衣服沒有被吹動。她只是看見——遠處的海面上方，有一團白色的光，無聲地亮起來。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是閃電。閃電是一瞬。這個光是持續的。它在擴大。像有人把亮度這個變量從零一口氣推到無限大，然後停在那裡。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她旁邊的人沒有被炸飛。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "步道上本來有幾個人——晨跑的、趕早班車的、抽菸的。他們沒有倒下。他們只是停了。晨跑的人停在原地，腳還維持著跑步的姿勢但沒有踏出去。抽菸的人手裡的菸掉在地上，他沒有去撿。有一個人嘴張著，像正在說什麼，但他的表情空白了——不是驚嚇，是忘記。像有人把他正在說的那句話從他腦子裡抽走了。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）他們會說那是救援⋯⋯不要救東京。", background: Background.Chapter_4_Ch4_Act8_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "千田的聲音。不是回憶。是直接在她腦子裡響起來的。像那束白光不只是照進她的眼睛，還塞進了什麼東西——一句話，一個畫面，一種她還來不及辨認的重量。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白光填滿了她的視野。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是變亮。是變白。所有的東西都失去了輪廓——欄杆、步道、海面、天空、她自己的手——全部融進白色裡。沒有痛。沒有聲音。只有白。和眼睛後方那種被填滿的感覺——像有東西正在被寫進去。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後白光收回了。像沒發生過。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她閉上眼。", background: Background.Chapter_4_Ch4_Act8_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機螢幕亮了。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是鬧鐘。是那種自己醒過來的亮——沒有聲音，沒有震動，只是螢幕從黑裡浮上來。朝倉澪睜開眼的時候，白光還黏在眼皮內側，摳不掉。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯白光。", background: Background.Chapter_4_Ch4_Act8_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是夢。夢不會留下這種殘影。夢醒來會散。這個沒有散。她的眼睛後方還是白的。太陽穴還在痛。和昨晚一樣的位置，一樣的力度，像有人按了一整夜沒鬆手。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她側過身，拿起手機。螢幕上的數字很亮。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "6:13。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）六點十三分。", background: Background.Chapter_4_Ch4_Act8_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把這幾個字在心裡念了一遍。像在確認什麼。然後她看見了日期。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯星期一。", background: Background.Chapter_4_Ch4_Act8_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是這個星期一。是上週一。千田還沒有上車的那個星期一。她還沒有收到匿名訊息的那個星期一。悠真失蹤第七天的早上。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有動。她躺在那裡，盯著螢幕上的日期，像盯著一個不應該存在的東西。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "防災測試的新聞正在播。同一則。和她醒來那天早上看到的一模一樣——同樣的畫面，同樣的標題，同樣的字。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她伸手去摸斜背包。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "摸空了。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手按在床邊，指尖碰到的是床單。不是背包的帶子。不是布料的觸感。她轉頭看——斜背包不在床邊。它掛在衣架上。和她每天晚上掛的位置一樣。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她坐起來。動作很慢。像一具沒上緊發條的東西。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "書桌。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "小鏡子在書桌上。悠真失蹤時間線筆記旁邊。和那天早上醒來時一模一樣的位置。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）鏡子⋯⋯在桌上。", background: Background.Chapter_4_Ch4_Act8_S1, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它不在她的包裡。它不在斜背包內層的小布套裡。它在書桌上。她記得她把它放進包裡——星期二凌晨，她從警署回來之後，她把它從書桌拿起來，放進斜背包內層。她記得那個動作。她記得布套的觸感。她記得拉鏈合上的聲音。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但鏡子在書桌上。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站起來。赤腳。地板涼。她沒有去拿拖鞋。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走到書桌前。拿起手機。再確認一次日期。上週一。沒有變。她沒有看錯。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走出房間。推開悠真的房門。", background: Background.Chapter_4_Ch4_Act8_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校服掛在椅背上。遊戲手把丟在桌上。那包未拆的零食還在。算式停在倒數第二步。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "書包靠在床腳。她彎腰翻了一下——裡面夾著那張說明單。「關東青少年睡眠支援計畫」。折成四折。角被壓皺了。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）還在。說明單還在。和那天早上看到的⋯⋯一模一樣。", background: Background.Chapter_4_Ch4_Act8_S2, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她回到自己的房間。拉開書桌抽屜。翻出那本舊筆記本。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她要找那一頁。星期二凌晨她寫下的時間線——千田的遺言、外殼的特徵、監視器缺段、7-CAM、有明車輛基地、三個矛盾。她寫了整整三頁。她記得筆尖壓下去的力道。她記得便條紙黏在頁面右側。她記得最後一行寫的是「不要救東京」，底下畫了兩條線。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻到那一頁。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那一頁是空白的。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是被撕掉。不是被擦掉。是從來沒有寫過。紙面乾淨，沒有筆痕，沒有便條紙的殘膠，沒有任何東西曾經存在過的痕跡。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯沒有。", background: Background.Chapter_4_Ch4_Act8_S2, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她往回翻。往前翻。整本筆記本裡沒有千田。沒有外殼。沒有第七車。沒有有明車輛基地。沒有時間線。沒有她寫下的任何一個字。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "因為那些字還沒有被寫下來。因為那一週還沒有發生。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外殼不在證物袋裡——因為千田還沒有上車。血衣不在警署——因為她還沒有按住傷口。問話紀錄不存在——因為她還沒有被帶進那間房間。新聞報導不存在——因為還沒有人死在第七車。有明車輛基地的封存條不存在——因為事故車還沒有發生事故。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它們不是消失了。它們是在這個星期一早上尚未發生。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只有澪記得。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她記得千田的手攥住她的手指。她記得外殼破邊在冷光下像刀。她記得監視器裡那個站在死者旁邊、滿手是血的女孩。她記得日下部說「妳父親以前也是這樣」。她記得東京灣的水黑得像夢裡的海。她記得白光。她記得那七秒。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她合上筆記本。把它放回抽屜。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有喊。她沒有哭。她坐在書桌前，看著那面小鏡子。鏡子背面朝上。受試者編號還在。悠真失蹤第七天還在。窗外灰藍色的光正在變白。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機螢幕上的時間停在 6:13。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "書桌上的世界還沒有開始那一週。", background: Background.Chapter_4_Ch4_Act8_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "只有澪已經失去過一次。", background: Background.Chapter_4_Ch4_Act8_S2 },
];
